WITH shipment_fn AS (SELECT p.oid,p.proacl,p.proowner,pg_get_functiondef(p.oid) AS definition FROM pg_proc p WHERE p.oid=to_regprocedure('public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid)')), adjust_fn AS (SELECT p.oid,p.proacl,p.proowner,pg_get_functiondef(p.oid) AS definition FROM pg_proc p WHERE p.oid=to_regprocedure('public.adjust_shipment_items_v1(uuid,jsonb,text)')) SELECT audit_issue,detail FROM (SELECT 'line_column_missing'::text AS audit_issue,'Thieu cot inventory_transactions.shipment_line_no'::text AS detail WHERE NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='inventory_transactions' AND column_name='shipment_line_no') UNION ALL SELECT 'partially_numbered_shipment','Mot chuyen da bat dau co thu tu nhung van con dong thieu thu tu' WHERE EXISTS (SELECT 1 FROM public.inventory_transactions t WHERE t.shipment_id IS NOT NULL AND t.tx_type='out' AND t.adjusted_from_transaction_id IS NULL AND t.deleted_at IS NULL GROUP BY t.shipment_id HAVING count(*) FILTER (WHERE t.shipment_line_no IS NOT NULL)>0 AND count(*) FILTER (WHERE t.shipment_line_no IS NULL)>0) UNION ALL SELECT 'invalid_numbered_sequence','Thu tu dong cua mot chuyen khong lien tuc tu 1' WHERE EXISTS (SELECT 1 FROM public.inventory_transactions t WHERE t.shipment_id IS NOT NULL AND t.tx_type='out' AND t.adjusted_from_transaction_id IS NULL AND t.deleted_at IS NULL AND t.shipment_line_no IS NOT NULL GROUP BY t.shipment_id HAVING min(t.shipment_line_no)<>1 OR max(t.shipment_line_no)<>count(*) OR count(DISTINCT t.shipment_line_no)<>count(*)) UNION ALL SELECT 'shipment_wrapper_missing','Thieu wrapper tao chuyen luu thu tu' WHERE NOT EXISTS (SELECT 1 FROM shipment_fn) UNION ALL SELECT 'shipment_wrapper_order_logic_missing','Wrapper tao chuyen khong luu thu tu payload' WHERE EXISTS (SELECT 1 FROM shipment_fn WHERE definition NOT ILIKE '%WITH ORDINALITY%' OR definition NOT ILIKE '%shipment_line_no%') UNION ALL SELECT 'adjust_wrapper_missing','Thieu wrapper dieu chinh chuyen luu thu tu' WHERE NOT EXISTS (SELECT 1 FROM adjust_fn) UNION ALL SELECT 'adjust_wrapper_order_logic_missing','Wrapper dieu chinh khong luu lai thu tu dong' WHERE EXISTS (SELECT 1 FROM adjust_fn WHERE definition NOT ILIKE '%WITH ORDINALITY%' OR definition NOT ILIKE '%shipment_line_no%') UNION ALL SELECT 'adjust_core_missing','Thieu core dieu chinh chuyen' WHERE to_regprocedure('public.adjust_shipment_items_core_20260723(uuid,jsonb,text)') IS NULL UNION ALL SELECT 'anon_can_create_shipment','anon van co quyen tao chuyen' WHERE to_regprocedure('public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid)') IS NOT NULL AND has_function_privilege('anon','public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid)','EXECUTE') UNION ALL SELECT 'anon_can_adjust_shipment','anon van co quyen dieu chinh chuyen' WHERE to_regprocedure('public.adjust_shipment_items_v1(uuid,jsonb,text)') IS NOT NULL AND has_function_privilege('anon','public.adjust_shipment_items_v1(uuid,jsonb,text)','EXECUTE') UNION ALL SELECT 'authenticated_cannot_create_shipment','authenticated khong co quyen goi wrapper tao chuyen' WHERE to_regprocedure('public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid)') IS NOT NULL AND NOT has_function_privilege('authenticated','public.shipment_outbound_delivery(jsonb,uuid,uuid,uuid,text,text,text,text,text,date,uuid)','EXECUTE') UNION ALL SELECT 'authenticated_cannot_adjust_shipment','authenticated khong co quyen goi wrapper dieu chinh chuyen' WHERE to_regprocedure('public.adjust_shipment_items_v1(uuid,jsonb,text)') IS NOT NULL AND NOT has_function_privilege('authenticated','public.adjust_shipment_items_v1(uuid,jsonb,text)','EXECUTE')) problems ORDER BY audit_issue;
